import{c as e,Q as a,j as s,m as r}from"./chunks/framework.BXc4yaFE.js";const g=JSON.parse('{"title":"Harness Beats Model Upgrades: 5 Benchmark Analysis — @MindStudio","description":"","frontmatter":{"title":"Harness Beats Model Upgrades: 5 Benchmark Analysis — @MindStudio","author":"MindStudio Engineering","date":"2026-05-05T00:00:00.000Z","source":"https://www.mindstudio.ai/blog/agent-harnesses-beat-model-upgrades-5-benchmarks","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-05-@mindstudio-harness-beats-model.md","filePath":"research/tweets/2026-05-05-@mindstudio-harness-beats-model.md","lastUpdated":1779894392000}'),d={name:"research/tweets/2026-05-05-@mindstudio-harness-beats-model.md"};function n(o,t,i,h,l,c){return a(),s("div",null,[...t[0]||(t[0]=[r('<h1 id="harness-beats-model-upgrades-5-benchmark-analysis-—-mindstudio" tabindex="-1">Harness Beats Model Upgrades: 5 Benchmark Analysis — @MindStudio <a class="header-anchor" href="#harness-beats-model-upgrades-5-benchmark-analysis-—-mindstudio" aria-label="Permalink to &quot;Harness Beats Model Upgrades: 5 Benchmark Analysis — @MindStudio&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://www.mindstudio.ai/blog/agent-harnesses-beat-model-upgrades-5-benchmarks" target="_blank" rel="noreferrer">https://www.mindstudio.ai/blog/agent-harnesses-beat-model-upgrades-5-benchmarks</a><strong>作者</strong>：MindStudio Engineering <strong>發布日期</strong>：2026-05-05（近似） <strong>收錄日期</strong>：2026-05-10 <strong>類型</strong>：Blog 研究 + 社群傳播推文 <strong>分類</strong>：eval / harness-design</p><hr><h2 id="核心數據" tabindex="-1">核心數據 <a class="header-anchor" href="#核心數據" aria-label="Permalink to &quot;核心數據&quot;">​</a></h2><blockquote><p>&quot;GPT-5.5 in native Codex harness: 61.5% SWE-Bench verified. Same model in Cursor harness: 87.2%. That&#39;s a 25.7pp swing from harness alone.&quot;</p></blockquote><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：5 個 benchmark 的分析證明 harness 工程現在超越模型升級對結果的貢獻。相同模型（GPT-5.5）在不同 harness 中的性能差距達 25.7 pp — 超過一個模型世代的提升。</p><h3 id="_5-benchmark-結果" tabindex="-1">5 Benchmark 結果 <a class="header-anchor" href="#_5-benchmark-結果" aria-label="Permalink to &quot;5 Benchmark 結果&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Benchmark</th><th>模型</th><th>Harness A</th><th>Harness B</th><th>差距</th></tr></thead><tbody><tr><td>SWE-Bench</td><td>GPT-5.5</td><td>Codex 61.5%</td><td>Cursor 87.2%</td><td>+25.7 pp</td></tr><tr><td>Terminal-Bench 2</td><td>Claude Sonnet</td><td>Base 64.2%</td><td>AHE-evolved 77.0%</td><td>+12.8 pp</td></tr><tr><td>HotpotQA</td><td>Claude Opus</td><td>Solo 31.7%</td><td>3-agent 74.3%</td><td>+42.6 pp</td></tr><tr><td>MATH</td><td>Haiku 4.5</td><td>No scaffold 52.1%</td><td>CoT+tools 78.4%</td><td>+26.3 pp</td></tr><tr><td>WebArena</td><td>GPT-5</td><td>Default 42.8%</td><td>Optimized 61.7%</td><td>+18.9 pp</td></tr></tbody></table><h3 id="關鍵結論" tabindex="-1">關鍵結論 <a class="header-anchor" href="#關鍵結論" aria-label="Permalink to &quot;關鍵結論&quot;">​</a></h3><ol><li><strong>Harness 影響 &gt; 模型升級影響</strong>：25.7 pp 差距超過 GPT-4 → GPT-5 的提升（~20 pp）</li><li><strong>最小 harness 提升</strong>：即使最保守的 harness 優化也帶來 12+ pp 提升</li><li><strong>飽和閾值</strong>：在已有強 harness 的基準上（AHE-evolved），模型升級仍有 8-15 pp 效果</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>相關性</td><td>9/10</td><td>直接量化 harness engineering 的 ROI vs 模型升級</td></tr><tr><td>可行動性</td><td>9/10</td><td>明確指向「先優化 harness 再考慮升級模型」</td></tr><tr><td>新穎性</td><td>8/10</td><td>量化比較首次跨 5 benchmarks 系統呈現</td></tr><tr><td><strong>總評</strong></td><td><strong>8.7/10</strong></td><td>—</td></tr></tbody></table><hr><h2 id="對-cc-workspace-的意涵" tabindex="-1">對 cc-workspace 的意涵 <a class="header-anchor" href="#對-cc-workspace-的意涵" aria-label="Permalink to &quot;對 cc-workspace 的意涵&quot;">​</a></h2><ol><li><strong>Model selection 決策</strong>：先問「harness 有沒有優化？」再問「要升級到哪個模型？」</li><li><strong>ROI 計算</strong>：harness 改善的 ROI &gt; 模型升級的 ROI（25.7 pp vs ~20 pp，且 harness 成本低）</li><li><strong>Subagent 策略驗證</strong>：HotpotQA 的 74.3% vs 31.7% 直接驗證 PGE 多代理設計的價值</li></ol><p><strong>相關</strong>：<code>subagent-strategy.md</code> §45% 規則（single-agent baseline &lt; 45% 時多代理效果最大）</p>',19)])])}const m=e(d,[["render",n]]);export{g as __pageData,m as default};
